// 🧩 Shopify → Odoo Contact Data Processor (Final Version by ChatGPT)

// ───────────────────────────────
//  Helper utilities
// ───────────────────────────────
const toStringSafe = (value) => (value ?? '').toString().trim();

// Get base customer data from Shopify trigger
const shop = $('Shopify Trigger').item?.json ?? {};

// Try to load metafields if they exist in the payload
// or if there’s a previous node “Shopify Get Metafields” before this
let metafields = [];

if (Array.isArray(shop.metafields)) {
  metafields = shop.metafields;
} else {
  const metaResp = $('HTTP Request')?.item?.json ?? {};
  metafields = Array.isArray(metaResp.metafields) ? metaResp.metafields : [];
}

// Convert GraphQL or REST metafield response to flat array
const toMetafieldArray = (raw) => {
  if (!raw) return [];
  if (Array.isArray(raw)) return raw;
  if (Array.isArray(raw.edges)) {
    return raw.edges
      .map((edge) => edge?.node ?? edge)
      .filter(Boolean);
  }
  return [];
};

metafields = toMetafieldArray(metafields);

// Helper to get metafield by key
const getMeta = (key) => {
  const normalizedKey = toStringSafe(key).toLowerCase();
  const meta = metafields.find(
    (item) => toStringSafe(item?.key).toLowerCase() === normalizedKey
  );
  return toStringSafe(meta?.value);
};

// ───────────────────────────────
//  Extract data from Odoo search result
// ───────────────────────────────
const extractExistingContact = () => {
  const incoming = $input.item?.json ?? {};
  if (!incoming) return null;
  if (Array.isArray(incoming.records)) return incoming.records[0] ?? null;
  if (Array.isArray(incoming.result)) return incoming.result[0] ?? null;
  return incoming;
};

const existingContact = extractExistingContact();
const existingId = existingContact?.id ?? null;

// ───────────────────────────────
//  Prepare and normalize core data
// ───────────────────────────────
const rawEmail = toStringSafe(shop.email);
const normalizedEmail = rawEmail.toLowerCase();

// Company name: priority → metafield → default_address.company
const companyMeta =
  getMeta('company_name') ||
  getMeta('company name') ||
  getMeta('companyname');
const companyFromAddress = toStringSafe(shop?.default_address?.company);
const companyName = companyMeta || companyFromAddress || '';



// Determine company or individual
let fullName = [shop.first_name, shop.last_name].filter(Boolean).join(' ').trim();
let isCompany = Boolean(companyName);

if (isCompany) {
  fullName = companyName;
} else if (!fullName) {
  fullName = normalizedEmail || 'Shopify Customer';
}

// ───────────────────────────────
//  Map You are → Odoo partner type
// ───────────────────────────────
const youAre = getMeta('you_are');
const youAreNormalized = toStringSafe(youAre).toLowerCase();

let partnerTypeValue = ''; // default: Others
switch (youAreNormalized) {
  case '':
  case 'none of the above':
    partnerTypeValue = 'CN';
    break;
  case 'architect':
    partnerTypeValue = 'DB - Design and build'; // Design and Build
    break;
  case 'contractor':
  case 'contractor - residential':
    partnerTypeValue = 'CONS - Contractor';
    break;
  case 'interior designer':
    partnerTypeValue = 'DE';
    break;
  default:
    partnerTypeValue = 'Others';
    break;
}

// ───────────────────────────────
//  Handle phone normalization
// ───────────────────────────────
const resolvePhoneCandidates = () => {
  const baseCandidates = [
    shop.phone,
    shop.phone_number,
    ...(Array.isArray(shop.addresses)
      ? shop.addresses.flatMap((addr) => [addr?.phone, addr?.phone_number])
      : []),
    shop.default_address?.phone,
    shop.default_address?.phone_number,
  ];
  return baseCandidates.map(toStringSafe).filter(Boolean);
};

const phoneCandidates = resolvePhoneCandidates();
const phoneRaw = phoneCandidates[0] ?? '';
const phoneClean = phoneRaw.replace(/[()\-\.\s]/g, '');

// ───────────────────────────────
//  Return final unified output
// ───────────────────────────────
let jsonOutput = {
  existing: Boolean(existingId),
  existing_id: existingId,
  email: normalizedEmail,
  phone_clean: phoneClean,
  company_name: companyName,
  you_are: youAre,
  x_partner_type: partnerTypeValue,
  is_company: isCompany,
  _debug_shop_payload: shop,
};

// Áp dụng logic riêng cho Company / Individual
if (isCompany) {
  jsonOutput.name = companyName; // hiển thị COMPANY NAME
  jsonOutput.x_studio_i_din_cng_ty = [shop.first_name, shop.last_name]
    .filter(Boolean)
    .join(' ')
    .trim(); // tên người đại diện
} else {
  jsonOutput.name = [shop.first_name, shop.last_name].filter(Boolean).join(' ').trim();
  jsonOutput.x_studio_i_din_cng_ty = ''; // có thể bỏ dòng này nếu không cần
}

return jsonOutput;
